from collections import deque

def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    # 收集所有任务
    all_tasks = set(deps.keys())
    for prereqs in deps.values():
        all_tasks.update(prereqs)

    # 构建邻接表和入度
    adj = {task: [] for task in all_tasks}
    in_degree = {task: 0 for task in all_tasks}

    for task, prereqs in deps.items():
        for p in prereqs:
            adj[p].append(task)
            in_degree[task] += 1

    # 初始化队列，加入所有入度为0的节点（按字典序）
    queue = sorted([task for task in all_tasks if in_degree[task] == 0])
    result = []

    while queue:
        current_layer = queue[:]  # 当前层的所有任务
        result.append(current_layer)

        next_candidates = []
        for task in current_layer:
            for neighbor in adj[task]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    next_candidates.append(neighbor)

        # 为下一层排序
        queue = sorted(next_candidates)

    # 检查是否有环（所有任务是否都被处理）
    if len(all_tasks) == sum(len(layer) for layer in result):
        return result
    else:
        return []
