from collections import OrderedDict

def solve(capacity: int, ops: list[str]) -> list[int]:
    results = []
    if capacity == 0:
        for op in ops:
            parts = op.split()
            if parts[0] == 'get':
                results.append(-1)
        return results

    cache = OrderedDict()
    for op in ops:
        parts = op.split()
        if parts[0] == 'get':
            key = int(parts[1])
            if key in cache:
                cache.move_to_end(key)
                results.append(cache[key])
            else:
                results.append(-1)
        else:
            key = int(parts[1])
            value = int(parts[2])
            if key in cache:
                cache[key] = value
                cache.move_to_end(key)
            else:
                if len(cache) >= capacity:
                    cache.popitem(last=False)
                cache[key] = value
    return results
