from heapq import *
from collections import defaultdict

def solve(nums: list[int], k: int) -> list[float]:
    def median(low, high, k):
        if k % 2 == 1:
            return -low[0]
        else:
            return (-low[0] + high[0]) / 2

    low = []   # max-heap (store negative)
    high = []  # min-heap
    delay = defaultdict(int)
    res = []
    size = 0

    for i, num in enumerate(nums):
        # insert
        if not low or num <= -low[0]:
            heappush(low, -num)
        else:
            heappush(high, num)
        size += 1

        # remove out-of-window elements lazily
        if i >= k:
            out = nums[i - k]
            delay[out] += 1
            size -= 1

        # balance heaps
        while len(low) - delay.get(-low[0], 0) > size - (size // 2):
            val = -heappop(low)
            delay[val] -= 1
            if delay[val] == 0:
                del delay[val]
            heappush(high, val)
        while len(high) - delay.get(high[0], 0) > size // 2:
            val = heappop(high)
            delay[val] -= 1
            if delay[val] == 0:
                del delay[val]
            heappush(low, -val)

        # clean delayed elements from heap tops
        while low and delay.get(-low[0], 0) > 0:
            val = -heappop(low)
            delay[val] -= 1
            if delay[val] == 0:
                del delay[val]
        while high and delay.get(high[0], 0) > 0:
            val = heappop(high)
            delay[val] -= 1
            if delay[val] == 0:
                del delay[val]

        # compute median
        if size == k:
            res.append(median(low, high, k))

    return res
```

