from collections import deque

def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    # 构建反向依赖图：被依赖包 -> 依赖它的包
    reverse_graph = {}
    # 初始化所有包（出现在deps键或依赖列表中的包）
    all_packages = set(deps.keys())
    for dependencies in deps.values():
        all_packages.update(dependencies)

    # 初始化反向依赖图
    for pkg in all_packages:
        reverse_graph[pkg] = []

    # 填充反向依赖图
    for pkg, dependencies in deps.items():
        for dep in dependencies:
            reverse_graph[dep].append(pkg)

    # BFS遍历获取所有受影响的包
    affected = set()
    queue = deque(changed)

    while queue:
        current = queue.popleft()
        if current in affected:
            continue
        affected.add(current)
        # 将当前包的所有直接依赖者加入队列
        for dependent in reverse_graph.get(current, []):
            if dependent not in affected:
                queue.append(dependent)

    # 按字典序排序并返回
    return sorted(affected)
```

